#include <stdlib.h>
#include <string.h>

struct token { char *lex; size_t len; };

struct token *parse(const char *input) {
	struct token *t = malloc(sizeof *t);
	t->len = strlen(input);
	t->lex = malloc(t->len + 1);
	memcpy(t->lex, input, t->len + 1);
	return t;
}

#include <stdlib.h>
#include <string.h>

struct token { char *lex; size_t len; };

struct token *parse(const char *input) {
	struct token *t = malloc(sizeof *t);
	if (t == NULL) return NULL;
	t->len = strlen(input);
	t->lex = malloc(t->len + 1);
	if (t->lex == NULL) { free(t); return NULL; }
	memcpy(t->lex, input, t->len + 1);
	return t;
}
